    // Valid message followed by extra bytes
    let mut payload = vec![0x08, 0x2a]; // field 1 (id) = 42
    payload.extend_from_slice(&[0xff, 0xfe, 0xfd]); // trailing garbage

    let result = decode_with_schema(&payload, &descriptor);
    assert!(result.is_err(), "Should fail with trailing data");

    match result {
        Err(DecodeError::SchemaMismatch(msg)) => {
