    // Encode tag as varint
    let mut remaining = tag;
    while remaining >= 0x80 {
        bytes.push((remaining as u8) | 0x80);
        remaining >>= 7;
    }
    bytes.push(remaining as u8);
    bytes.push(0x01); // value = 1

